const update = $input.first().json;
const userId = update.message?.from?.id
  || update.callback_query?.from?.id
  || update.result?.chat?.id
  || update.result?.from?.id;
const callbackId = update.callback_query?.id || null;
if (!userId) {
  throw new Error('Не вдалося визначити користувача для перевірки підписки.'); //text mes in your language
}

return [{
  json: {
    user_id: userId,
    chat_id: '-1001234567890', // For private channels, use the full numeric ID starting with -100 or id ex:nikolenkoclub
    callback_query_id: callbackId
  }
}];
